/* ---------- Key-event card glow animation ---------- */
/*
 * Golden box-shadow pulse on the Revolución de Mayo and Caseros cards.
 * Fires once when .reveal--visible is added by the Intersection Observer.
 * The 0.3s delay lets the reveal fade-in begin before the glow fires.
 *
 * Inspectable at runtime:
 *   document.querySelectorAll('.card--key-event')  → should return 2 elements
 *   getComputedStyle(card).animation               → shows animation shorthand
 *   card.classList.contains('reveal--visible')     → true after scroll-reveal
 *
 * Failure modes:
 *   - 0 results from querySelectorAll → class missing from index.html
 *   - animation never plays → check .reveal--visible is being added by JS observer
 *   - glow repeats → verify 'forwards' fill mode and no 'infinite' iteration count
 *   - glow visible in reduced-motion → check @media block below overrides correctly
 */
@keyframes key-event-glow {
  0%   { box-shadow: 0 0 0    0   rgba(184, 134, 11, 0);    }
  40%  { box-shadow: 0 0 20px 4px rgba(184, 134, 11, 0.25); }
  100% { box-shadow: 0 0 0    0   rgba(184, 134, 11, 0);    }
}

.reveal--visible.card--key-event {
  animation: key-event-glow 1.2s ease-in-out 0.3s forwards;
}

@media (prefers-reduced-motion: reduce) {
  .card--key-event {
    animation: none;
  }
}

